  1	# frozen_string_literal: true
  2	
  3	require "spec_helper"
  4	
  5	RSpec.describe "MCP type coercion" do
  6	  let(:test_class) do
  7	    Class.new do
  8	      include Raix::ChatCompletion
  9	      include Raix::MCP
 10	
 11	      def self.name
 12	        "TestMcpTypeCoercion"
 13	      end
 14	    end
 15	  end
 16	
 17	  it "coerces string numbers to numeric types based on schema" do
 18	    instance = test_class.new
 19	
 20	    # Test integer coercion
 21	    schema = {
 22	      "properties" => {
 23	        "x" => { "type" => "integer" },
 24	        "y" => { "type" => "number" },
 25	        "enabled" => { "type" => "boolean" },
 26	        "items" => { "type" => "array" },
 27	        "data" => { "type" => "object" }
 28	      }
 29	    }
 30	
 31	    arguments = {
 32	      "x" => "100",
 33	      "y" => "50.5",
 34	      "enabled" => "true",
 35	      "items" => "[1, 2, 3]",
 36	      "data" => '{"key": "value"}'
 37	    }
 38	
 39	    result = instance.send(:coerce_arguments, arguments, schema)
 40	
 41	    expect(result["x"]).to eq(100)
 42	    expect(result["x"]).to be_a(Integer)
 43	
 44	    expect(result["y"]).to eq(50.5)
 45	    expect(result["y"]).to be_a(Float)
 46	
 47	    expect(result["enabled"]).to eq(true)
 48	    expect(result["enabled"]).to be_a(TrueClass)
 49	
 50	    expect(result["items"]).to eq([1, 2, 3])
 51	    expect(result["items"]).to be_a(Array)
 52	
 53	    expect(result["data"]).to eq({ "key" => "value" })
 54	    expect(result["data"]).to be_a(Hash)
 55	  end
 56	
 57	  it "preserves non-string values" do
 58	    instance = test_class.new
 59	
 60	    schema = {
 61	      "properties" => {
 62	        "x" => { "type" => "integer" },
 63	        "y" => { "type" => "number" }
 64	      }
 65	    }
 66	
 67	    arguments = { "x" => 100, "y" => 50.5 }
 68	    result = instance.send(:coerce_arguments, arguments, schema)
 69	
 70	    expect(result["x"]).to eq(100)
 71	    expect(result["y"]).to eq(50.5)
 72	  end
 73	
 74	  it "coerces arrays of objects with item schemas" do
 75	    instance = test_class.new
 76	
 77	    schema = {
 78	      "properties" => {
 79	        "users" => {
 80	          "type" => "array",
 81	          "items" => {
 82	            "type" => "object",
 83	            "properties" => {
 84	              "id" => { "type" => "integer" },
 85	              "age" => { "type" => "number" },
 86	              "active" => { "type" => "boolean" }
 87	            }
 88	          }
 89	        }
 90	      }
 91	    }
 92	
 93	    arguments = {
 94	      "users" => [
 95	        { "id" => "123", "age" => "25.5", "active" => "true" },
 96	        { "id" => "456", "age" => "30", "active" => "false" }
 97	      ]
 98	    }
 99	
100	    result = instance.send(:coerce_arguments, arguments, schema)
101	
102	    expect(result["users"]).to be_a(Array)
103	    expect(result["users"].length).to eq(2)
104	
105	    first_user = result["users"][0]
106	    expect(first_user["id"]).to eq(123)
107	    expect(first_user["id"]).to be_a(Integer)
108	    expect(first_user["age"]).to eq(25.5)
109	    expect(first_user["age"]).to be_a(Float)
110	    expect(first_user["active"]).to eq(true)
111	    expect(first_user["active"]).to be_a(TrueClass)
112	
113	    second_user = result["users"][1]
114	    expect(second_user["id"]).to eq(456)
115	    expect(second_user["active"]).to eq(false)
116	  end
117	
118	  it "handles nested object coercion" do
119	    instance = test_class.new
120	
121	    schema = {
122	      "properties" => {
123	        "config" => {
124	          "type" => "object",
125	          "properties" => {
126	            "settings" => {
127	              "type" => "object",
128	              "properties" => {
129	                "max_retries" => { "type" => "integer" },
130	                "timeout" => { "type" => "number" },
131	                "debug" => { "type" => "boolean" }
132	              }
133	            },
134	            "metadata" => {
135	              "type" => "object",
136	              "properties" => {
137	                "version" => { "type" => "number" }
138	              }
139	            }
140	          }
141	        }
142	      }
143	    }
144	
145	    arguments = {
146	      "config" => {
147	        "settings" => {
148	          "max_retries" => "3",
149	          "timeout" => "30.5",
150	          "debug" => "true"
151	        },
152	        "metadata" => {
153	          "version" => "1.2"
154	        }
155	      }
156	    }
157	
158	    result = instance.send(:coerce_arguments, arguments, schema)
159	
160	    expect(result["config"]["settings"]["max_retries"]).to eq(3)
161	    expect(result["config"]["settings"]["max_retries"]).to be_a(Integer)
162	    expect(result["config"]["settings"]["timeout"]).to eq(30.5)
163	    expect(result["config"]["settings"]["timeout"]).to be_a(Float)
164	    expect(result["config"]["settings"]["debug"]).to eq(true)
165	    expect(result["config"]["metadata"]["version"]).to eq(1.2)
166	  end
167	
168	  it "handles JSON string inputs for arrays and objects" do
169	    instance = test_class.new
170	
171	    schema = {
172	      "properties" => {
173	        "tags" => { "type" => "array" },
174	        "config" => {
175	          "type" => "object",
176	          "properties" => {
177	            "enabled" => { "type" => "boolean" }
178	          }
179	        }
180	      }
181	    }
182	
183	    arguments = {
184	      "tags" => '["tag1", "tag2", "tag3"]',
185	      "config" => '{"enabled": "true", "extra": "value"}'
186	    }
187	
188	    result = instance.send(:coerce_arguments, arguments, schema)
189	
190	    expect(result["tags"]).to eq(%w[tag1 tag2 tag3])
191	    expect(result["config"]["enabled"]).to eq(true)
192	    expect(result["config"]["extra"]).to eq("value") # preserves extra properties
193	  end
194	
195	  it "handles invalid JSON gracefully" do
196	    instance = test_class.new
197	
198	    schema = {
199	      "properties" => {
200	        "data" => { "type" => "array" }
201	      }
202	    }
203	
204	    arguments = {
205	      "data" => "not valid json ["
206	    }
207	
208	    result = instance.send(:coerce_arguments, arguments, schema)
209	
210	    # Should return the original value when JSON parsing fails
211	    expect(result["data"]).to eq("not valid json [")
212	  end
213	
214	  it "handles type mismatches gracefully" do
215	    instance = test_class.new
216	
217	    schema = {
218	      "properties" => {
219	        "count" => { "type" => "integer" },
220	        "ratio" => { "type" => "number" },
221	        "flag" => { "type" => "boolean" }
222	      }
223	    }
224	
225	    arguments = {
226	      "count" => "not a number",
227	      "ratio" => "also not a number",
228	      "flag" => "maybe"
229	    }
230	
231	    result = instance.send(:coerce_arguments, arguments, schema)
232	
233	    # Should return original values when coercion is not possible
234	    expect(result["count"]).to eq("not a number")
235	    expect(result["ratio"]).to eq("also not a number")
236	    expect(result["flag"]).to eq("maybe")
237	  end
238	
239	  it "preserves additional properties not in schema" do
240	    instance = test_class.new
241	
242	    schema = {
243	      "properties" => {
244	        "known" => { "type" => "integer" }
245	      }
246	    }
247	
248	    arguments = {
249	      "known" => "42",
250	      "unknown" => "value",
251	      "extra" => { "nested" => true }
252	    }
253	
254	    result = instance.send(:coerce_arguments, arguments, schema)
255	
256	    expect(result["known"]).to eq(42)
257	    expect(result["unknown"]).to eq("value")
258	    expect(result["extra"]).to eq({ "nested" => true })
259	  end
260	
261	  it "handles symbol and string keys interchangeably" do
262	    instance = test_class.new
263	
264	    schema = {
265	      "properties" => {
266	        "value" => { "type" => "integer" }
267	      }
268	    }
269	
270	    arguments = {
271	      value: "100" # symbol key
272	    }
273	
274	    result = instance.send(:coerce_arguments, arguments, schema)
275	
276	    expect(result["value"]).to eq(100)
277	    expect(result[:value]).to eq(100) # with_indifferent_access allows both
278	  end
279	
280	  it "handles nil values appropriately" do
281	    instance = test_class.new
282	
283	    schema = {
284	      "properties" => {
285	        "optional_int" => { "type" => "integer" },
286	        "optional_bool" => { "type" => "boolean" }
287	      }
288	    }
289	
290	    arguments = {
291	      "optional_int" => nil,
292	      "other_field" => "value"
293	    }
294	
295	    result = instance.send(:coerce_arguments, arguments, schema)
296	
297	    # nil values are preserved as-is (not coerced)
298	    expect(result["optional_int"]).to be_nil
299	    expect(result["other_field"]).to eq("value")
300	  end
301	
302	  it "coerces boolean edge cases correctly" do
303	    instance = test_class.new
304	
305	    schema = {
306	      "properties" => {
307	        "bool1" => { "type" => "boolean" },
308	        "bool2" => { "type" => "boolean" },
309	        "bool3" => { "type" => "boolean" },
310	        "bool4" => { "type" => "boolean" }
311	      }
312	    }
313	
314	    arguments = {
315	      "bool1" => true,
316	      "bool2" => false,
317	      "bool3" => "true",
318	      "bool4" => "false"
319	    }
